SELECT 'Order' as "State", OrderH.REF as "Reference", OrderH.ORDDATE as "Order_Date", OrderH.UF_SHIPOUT as "Ship_Out_Date", OrderH.CUSTCODE, OrderH.COMPANY as "Company_Name", OrderI.PRODUCT, OrderI.DESC1, OrderI.QUANTITY, OrderI.CUNIT, OrderI.PRICE as "Case_Price", OrderI.COST, OrderI.TOTNET as "Line_Value", OrderH.UF_ACCHAND as "IBM" FROM NISAINT_CS\OrderH OrderH LEFT JOIN OrderI ON OrderI.REF = OrderH.REF WHERE OrderH.INSTATUS = 1 AND OrderH.OHINVREF IS NULL AND LEFT(OrderI.PRODUCT, 1) IN ('7', '8', '9') UNION SELECT 'Quote' as "State", QUOTEH.REF, QUOTEH.ORDDATE as "Order_Date", QUOTEH.UF_SHIPOUT as "Ship_Out_Date", QuoteH.CUSTCODE, QuoteH.COMPANY as "Company_Code", QuoteI.PRODUCT, QuoteI.DESC1, QuoteI.QUANTITY, QuoteI.CUNIT, QuoteI.PRICE as "Case_Price", QuoteI.COST, QuoteI.TOTNET as "Line_Value", QuoteH.UF_ACCHAND as "IBM" FROM NISAINT_CS\QUOTEH QUOTEH LEFT JOIN QuoteI ON QuoteI.REF = QuoteH.REF WHERE QUOTEH.INSTATUS = 1 AND QUOTEH.QTRESULTORDERREF IS NULL AND LEFT(QuoteI.PRODUCT, 1) IN ('7', '8', '9');
